module top_module(data_in_a, in2, c, aluout);input [2:0] data_in_a, in2;
input [1:0] c;
output reg [2:0] aluout;
always @ (data_in_a, in2, c)
    begin
        case (c)
            2'b11:  aluout = data_in_a + in2;
            2'b10:  aluout = data_in_a - in2;
            2'b01:  aluout = data_in_a & in2;
